// 模拟数据库连接
const mockDb = {
  raw: jest.fn().mockResolvedValue({ rows: [{ test: 1 }] }),
  destroy: jest.fn().mockResolvedValue(),
  insert: jest.fn().mockResolvedValue(),
  where: jest.fn().mockReturnThis(),
  del: jest.fn().mockResolvedValue(),
  update: jest.fn().mockResolvedValue()
};

// 模拟数据库模块
const db = mockDb;

// 设置测试环境变量
process.env.NODE_ENV = 'test';
process.env.DATABASE_URL = process.env.DATABASE_URL || 'postgresql://postgres:postgres@localhost:5432/funnypixels_test';
process.env.REDIS_URL = process.env.REDIS_URL || 'redis://localhost:6379/1';

// 全局测试设置
beforeAll(async () => {
  console.log('🚀 开始测试环境设置...');
  
  try {
    // 确保数据库连接
    await db.raw('SELECT 1');
    console.log('✅ 数据库连接成功');
    
    // 清理测试数据
    await cleanupTestData();
    console.log('✅ 测试数据清理完成');
    
  } catch (error) {
    console.error('❌ 测试环境设置失败:', error);
    throw error;
  }
});

// 每个测试后清理
afterEach(async () => {
  try {
    await cleanupTestData();
  } catch (error) {
    console.warn('⚠️ 测试后清理失败:', error);
  }
});

// 所有测试完成后清理
afterAll(async () => {
  console.log('🧹 清理测试环境...');
  
  try {
    await cleanupTestData();
    await db.destroy();
    console.log('✅ 测试环境清理完成');
  } catch (error) {
    console.error('❌ 测试环境清理失败:', error);
  }
});

// 清理测试数据的函数
async function cleanupTestData() {
  const tables = [
    'wallet_ledger',
    'user_inventory',
    'recharge_orders',
    'idempotency_keys'
  ];
  
  for (const table of tables) {
    try {
      await db(table).del();
    } catch (error) {
      // 表可能不存在，忽略错误
    }
  }
  
  // 清理测试用户（用户名以 test 开头）
  try {
    await db('users').where('username', 'like', 'test%').del();
    await db('users').where('username', 'like', 'perftest%').del();
    await db('users').where('username', 'like', 'e2etest%').del();
  } catch (error) {
    // 忽略错误
  }
  
  // 清理测试商品（名称包含测试）
  try {
    await db('store_items').where('name', 'like', '%测试%').del();
    await db('store_items').where('name', 'like', '%性能测试%').del();
  } catch (error) {
    // 忽略错误
  }
}

// 全局测试工具函数
global.createTestUser = async (userData = {}) => {
  const { v4: uuidv4 } = require('uuid');
  
  const defaultUser = {
    id: uuidv4(),
    username: `testuser_${Date.now()}`,
    email: `test_${Date.now()}@example.com`,
    points: 1000,
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString()
  };
  
  const user = { ...defaultUser, ...userData };
  
  await db('users').insert(user);
  return user;
};

global.createTestItem = async (itemData = {}) => {
  const { v4: uuidv4 } = require('uuid');
  
  const defaultItem = {
    id: uuidv4(),
    name: `测试商品_${Date.now()}`,
    type: 'pixel_boost',
    price_points: 100,
    active: true,
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString()
  };
  
  const item = { ...defaultItem, ...itemData };
  
  await db('store_items').insert(item);
  return item;
};

global.cleanupTestUser = async (userId) => {
  try {
    await db('users').where('id', userId).del();
  } catch (error) {
    // 忽略错误
  }
};

global.cleanupTestItem = async (itemId) => {
  try {
    await db('store_items').where('id', itemId).del();
  } catch (error) {
    // 忽略错误
  }
};

// 模拟认证中间件
global.mockAuth = (req, res, next) => {
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Bearer test-token-')) {
    const userId = authHeader.replace('Bearer test-token-', '');
    req.user = { id: userId };
    next();
  } else {
    res.status(401).json({ success: false, error: '认证失败' });
  }
};

// 测试超时设置
jest.setTimeout(30000);

console.log('📋 测试环境配置完成');
